package paginator
import ("reflect"; "testing")
func TestGTPaginate(t *testing.T) {
	items := []int{1,2,3,4,5,6,7}
	if !reflect.DeepEqual(Page(items,1,3), []int{1,2,3}) { t.Fatalf("p1=%v", Page(items,1,3)) }
	if !reflect.DeepEqual(Page(items,3,3), []int{7}) { t.Fatalf("p3=%v", Page(items,3,3)) }
	if Page(items,4,3) != nil { t.Fatalf("p4 should be empty got %v", Page(items,4,3)) }
	if !reflect.DeepEqual(LastPage(items,3), []int{7}) { t.Fatalf("last=%v", LastPage(items,3)) }
	if !reflect.DeepEqual(LastPage([]int{1,2,3,4},2), []int{3,4}) { t.Fatalf("last2=%v", LastPage([]int{1,2,3,4},2)) }
}
EOF
